  "direction": "Thanh Tùng đàm phán thành công khế ước luân canh với Lục Diệp Môn, giữ lại Hoang Mộc Điền và bước đầu giải quyết khủng hoảng tài chính, đồng thời hỗ trợ Thanh An phát triển bách nghệ.",
  "terminalChange": "Hoang Mộc Điền không bị bán đứt mà được chuyển sang cho thuê 20 năm. Thanh gia nhận được khoản linh thạch đầu tiên để duy trì hoạt động, Thanh An chính thức bắt đầu con đường thợ khảm ngọc, và uy tín của Thanh Tùng bước đầu được thiết lập.",
  "activeConflicts": [
    {
      "id": "conflict_internal_finance",
      "actorIds": [
        "char_01",
        "char_04",
        "char_02"
      ],
      "objective": "Quyết định phương án xử lý Hoang Mộc Điền để giải quyết khủng hoảng tài chính ngay lập tức.",
      "leverage": "Tam trưởng lão nắm quyền quản lý sổ sách và áp lực nợ nần ngắn hạn; Thanh Tùng nắm giữ thông tin về nhu cầu thực sự của Lục Diệp Môn.",
      "nextMove": "Thanh Tùng rời từ đường đi gặp Diệp Khê để đàm phán, trong khi Tam trưởng lão chuẩn bị sẵn khế ước bán đứt để ép Tộc trưởng ký ngay khi thời hạn ba ngày kết thúc."
    },
    {
      "id": "conflict_negotiation_lucdiep",
      "actorIds": [
        "char_01",
        "char_03"
      ],
      "objective": "Đạt được thỏa thuận thuê đất có lợi cho cả hai bên mà không làm mất quyền sở hữu cốt lõi của Thanh gia.",
      "leverage": "Diệp Khê cần Xích Nê Khoáng ẩn dưới Hoang Mộc Điền để phát triển bách nghệ; Thanh Tùng yêu cầu Lục Diệp Môn dùng Mộc Tẩy Thuật để phục hồi linh khí cho đất.",
      "nextMove": "Thanh Tùng tiết lộ bí mật về Xích Nê Khoáng để ép Diệp Khê từ bỏ ý định mua đứt và chấp nhận ngồi vào bàn đàm phán khế ước luân canh 20 năm."
    }
  ],
  "duePromiseIds": [
    "prom_01",
    "prom_03"
  ],
  "progressionBudget": [
    {
      "signal": "Thái độ của các trưởng lão chuyển từ hoài nghi sang tin tưởng",
      "requiredChange": "Thanh Tùng mang về bản khế ước cho thuê kèm theo khoản tiền cọc linh thạch đủ để giải quyết khủng hoảng ngắn hạn, đập tan sự phản đối của Tam trưởng lão."
    },
    {
      "signal": "Con số Tổ Nghiệp Nợ giảm xuống",
      "requiredChange": "Khi khế ước được ký kết dưới sự chứng giám của cây Thanh Tùng, con số nợ -3 Đời trên Hoang Mộc Điền bắt đầu mờ đi, chứng minh phương pháp luân canh có hiệu quả."
    }
  ]
